import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { Vehicle } from '../../core/data.models';
import { VehiclesService } from '../../services/vehicles.service';

@Component({
  selector: 'app-vehicles-detail',
  templateUrl: './vehicles-detail.component.html'
})
export class VehiclesDetailComponent implements OnInit {
  item?: Vehicle;

  constructor(private route: ActivatedRoute, private router: Router, private svc: VehiclesService) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.svc.list$.subscribe(list => {
      this.item = list.find(i => i.id === id);
      if (!this.item) this.router.navigate(['/vehicles']);
    });
  }
}
<div *ngIf="item" class="card">
  <h2>{{item.make}} {{item.model}}</h2>
  <div class="small">Year: {{item.year}}</div>
  <div style="margin-top:8px">VIN: {{item.vin || '—'}}</div>
  <div style="margin-top:8px">Mileage: {{item.mileage || '—'}} km</div>
  <div style="margin-top:8px">Last Service: {{item.lastServiceDate || '—'}}</div>
  <div style="margin-top:12px">
    <a [routerLink]="[item.id, 'edit']">Edit</a>
    <a routerLink="/vehicles" style="margin-left:8px">Back</a>
  </div>
</div>
